SELECT mp.question, mp.answer, mp.accuracy, mp.test_set_accuracy
FROM model_performance mp
WHERE mp.accuracy = (SELECT MAX(accuracy) FROM model_performance);

SELECT model_id, question, AVG(accuracy) AS average_accuracy
FROM model_performance
GROUP BY model_id, question;

SELECT question, answer, accuracy, evaluation_date
FROM model_performance
WHERE accuracy > 80;

SELECT actor_id, name
FROM actors
WHERE actor_id IN (
    SELECT movie_actor.actor_id
    FROM movie_actor 
    INNER JOIN movies ON movie_actor.movie_id = movies.movie_id
    WHERE movies.movie_id = (
        SELECT movie_id FROM movies WHERE budget = (SELECT MAX(budget) FROM movies)
    )
);
